namespace sv_5a487097b21b409093bd9f43d53af1a1.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Progress bar showing all steps with clickable completed steps *@

<nav class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-indicator">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = stepIndex < CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="text-center flex-fill step-item @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button type="button" class="btn btn-link p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="d-block small mt-1 text-success fw-semibold">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@(stepIndex + 1)</span>
                        <span class="d-block small mt-1 @(isCurrent ? "fw-semibold text-primary" : "text-muted")">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

<style>
    .step-circle {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 36px;
        height: 36px;
        border-radius: 50%;
        font-size: 0.85rem;
        font-weight: 600;
    }
</style>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];
}

@* A single work history entry with company, title, dates, and description *@

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Position @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@FormatDate(Entry.StartDate)"
                       @onchange="e => Update(Entry with { StartDate = ParseDate(e.Value) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@FormatDate(Entry.EndDate)"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = ParseNullableDate(e.Value) })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent"
                           @onchange="e => ToggleCurrent((bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void ToggleCurrent(bool isCurrent)
    {
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        OnChanged.InvokeAsync(updated);
    }

    private static string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
    private static string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");
    private static DateTime ParseDate(object? value) => DateTime.TryParse(value?.ToString(), out var d) ? d : default;
    private static DateTime? ParseNullableDate(object? value) => DateTime.TryParse(value?.ToString(), out var d) ? d : null;
}

@* A single reference entry with name, relationship, email, phone *@

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Reference @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Reference.Name"
                       @onchange="e => Update(Reference with { Name = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Reference.Relationship"
                       @onchange="e => Update(Reference with { Relationship = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" value="@Reference.Email"
                       @onchange="e => Update(Reference with { Email = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Reference.Phone"
                       @onchange="e => Update(Reference with { Phone = (string?)e.Value ?? "" })" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Reference Reference { get; set; } = default!;
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<Reference> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private void Update(Reference updated) => OnChanged.InvokeAsync(updated);
}

@* Step 1: Personal information — full name, email, phone, address *@

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.FullName"
               @onchange="e => UpdateModel(Model with { FullName = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Model.Email"
               @onchange="e => UpdateModel(Model with { Email = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.Phone"
               @onchange="e => UpdateModel(Model with { Phone = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.Address"
               @onchange="e => UpdateModel(Model with { Address = (string?)e.Value ?? "" })" />
    </div>
</div>

<div class="mt-4 d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnModelChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private void UpdateModel(PersonalInfo updated) => OnModelChanged.InvokeAsync(updated);

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@* Step 2: Work history — dynamic list of work entries *@

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="@Entries[index]"
                   Index="@(index + 1)"
                   CanRemove="@(Entries.Count > 1)"
                   OnChanged="entry => UpdateEntry(index, entry)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnEntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void UpdateEntry(int index, WorkEntry updated)
    {
        var list = new List<WorkEntry>(Entries) { [index] = updated };
        OnEntriesChanged.InvokeAsync(list);
    }

    private void RemoveEntry(int index)
    {
        var list = new List<WorkEntry>(Entries);
        list.RemoveAt(index);
        OnEntriesChanged.InvokeAsync(list);
    }

    private void AddEntry()
    {
        var list = new List<WorkEntry>(Entries)
        {
            new("", "", default, null, "")
        };
        OnEntriesChanged.InvokeAsync(list);
    }

    private void HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == default)
            {
                ErrorMessage = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        OnNext.InvokeAsync();
    }
}

@* Step 3: References — 2 to 3 references *@

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="@References[index]"
                   Index="@(index + 1)"
                   CanRemove="@(References.Count > 2)"
                   OnChanged="r => UpdateReference(index, r)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References) { [index] = updated };
        OnReferencesChanged.InvokeAsync(list);
    }

    private void RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        OnReferencesChanged.InvokeAsync(list);
    }

    private void AddReference()
    {
        var list = new List<Reference>(References)
        {
            new("", "", "", "")
        };
        OnReferencesChanged.InvokeAsync(list);
    }

    private void HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "At least 2 references are required.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        OnNext.InvokeAsync();
    }
}

@* Step 4: Cover letter with character count *@

<h4 class="mb-3">Cover Letter</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="mb-2">
    <textarea class="form-control" rows="12" value="@CoverLetter"
              @oninput="HandleInput"
              maxlength="2000"></textarea>
</div>
<div class="text-muted small mb-4">
    @(CoverLetter?.Length ?? 0) / 2000 characters
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnCoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void HandleInput(ChangeEventArgs e)
    {
        var text = (string?)e.Value ?? "";
        if (text.Length > 2000) text = text[..2000];
        OnCoverLetterChanged.InvokeAsync(text);
    }

    private void HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "A cover letter is required.";
            return;
        }

        OnNext.InvokeAsync();
    }
}

@* Step 5: Review all entered data and submit *@

<h4 class="mb-3">Review & Submit</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p>Your application has been submitted successfully. Your application ID is <strong>@SubmittedId</strong>.</p>
    </div>
}
else
{
    @* Personal Info Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    @* Work History Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <span class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") — @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
