@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References) { [index] = updated };
        OnReferencesChanged.InvokeAsync(list);
    }

    private void RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        OnReferencesChanged.InvokeAsync(list);
    }

    private void AddReference()
    {
        var list = new List<Reference>(References)
        {
            new("", "", "", "")
        };
        OnReferencesChanged.InvokeAsync(list);
    }

    private void HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "At least 2 references are required.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
